// Solution
#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

class Solution {
public:
bool compare(int a, int b, int digit) {
    return (a % (b + 1)) < (b % (a + 1));
}
void radixSort(vector<int>& nums) {
    // Corrected implementation using counting sort
    int max_val = *max_element(nums.begin(), nums.end());
    int exp = 1;
    while (max_val / exp > 0) {
        // Initialize count array
        vector<int> count(10, 0);

        // Count occurrences of each digit
        for (int i = 0; i < nums.size(); i++) {
            int digit = (nums[i] / exp) % 10;
            count[digit]++;
        }

        // Calculate cumulative counts
        for (int i = 1; i < 10; i++) {
            count[i] += count[i - 1];
        }

        // Build output array
        vector<int> output(nums.size());
        for (int i = nums.size() - 1; i >= 0; i--) {
            int digit = (nums[i] / exp) % 10;
            output[count[digit] - 1] = nums[i];
            count[digit]--;
        }

        // Update input array
        nums = output;

        // Move to next digit
        exp *= 10;
    }
}
};
int main() {
    // Read input
    int n;
    cin >> n;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) {
        cin >> nums[i];
    }

    // Perform radix sort
    Solution solution;
    solution.radixSort(nums);

    // Print output
    for (int i = 0; i < nums.size(); i++) {
        cout << nums[i] << ' ';n}
    return 0;
}
